from typing import Set, List, Optional, Iterable

import numpy as np
import tensorflow.compat.v1 as tf
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.bundle_classifier import get_bundle_classifier_from_name
from geosat.psanp.abstractions.bundler import Bundle
from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata

from psanp.classifiers.tensorflow.susann_classifier.laz_loader import LazLoader
from psanp.classifiers.tensorflow.susann_classifier.settings import Settings


def load_graph(string_protobuf, tensors):
    graph_def = tf.GraphDef()
    graph_def.ParseFromString(string_protobuf)
    graph_input = tf.import_graph_def(graph_def, name="")

    sess = tf.Session(graph=graph_input)
    graph = tf.get_default_graph()

    tensors_dict = {}
    for tensor in tensors:
        tensors_dict[tensor] = graph.get_tensor_by_name(tensor + ":0")

    return sess, tensors_dict


class SusannClassifier(Classifier):
    def __init__(
        self, refine_ground=True, discard_noise=False, stage_name: Optional[str] = None
    ):
        super().__init__(stage_name)
        tf.disable_v2_behavior()
        self.refine_ground = refine_ground
        self.discard_noise = discard_noise
        bundle: Bundle = get_bundle_classifier_from_name(self.stage_name)
        self._import_training_data(**bundle["database"])

    def _import_training_data(self, model_weights, config_file):
        self.sess, self.tensors_dict = load_graph(
            model_weights, ["input_placeholder", "flag_placeholder", "network/y_seg"]
        )
        self.config = Settings()
        self.config.read_config(config_file.decode("ascii"))

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "refine_ground",
                "Should the classification be refined around the ground "
                "to provide a better segmentation. (Default True)",
                type_cast=bool,
                required=False,
            ),
            Option(
                "discard_noise",
                "Should the classification filter out points labelled 'noise'. (Default False)",
                type_cast=bool,
                required=False,
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if not cloud:
            return (cloud,)
        if self.discard_noise and "noise" in pipeline_metadata.classification_codes:
            input_mask = (
                cloud.classification != pipeline_metadata.classification_codes["noise"]
            )
        else:
            input_mask = np.ones_like(cloud.classification, dtype="bool")
        loader = LazLoader(cloud[input_mask], self.config)

        # Processing dataset
        num_iter = loader.get_iterations_number()
        for _ in range(num_iter):
            # Read and process one batch
            voxels, mask = loader.read_batch()
            data_seg = self.sess.run(
                self.tensors_dict["network/y_seg"],
                feed_dict={
                    self.tensors_dict["input_placeholder"]: voxels,
                    self.tensors_dict["flag_placeholder"]: False,
                },
            )

            # Project results on point cloud
            loader.project_batch(data_seg, mask)

        # Map voxel-level annotation to 3D points
        loader.map_voxels_labels_to_pointcloud()

        # If ground refinement is required
        if self.refine_ground:
            loader.refine_ground()

        # Remapping to user classification codes
        mapping = np.array(
            [
                pipeline_metadata.classification_codes[class_name]
                for class_name in self.config.data.class_names
            ]
        )
        cloud.classification[input_mask] = mapping[loader.laz.classification]

        return (cloud,)

    def input_classes(self) -> Set[str]:
        return set()

    def output_classes(self) -> Set[str]:
        return set(self.config.data.class_names)
